import{_ as a,a as t,b as s,c as i,d as n,e as o}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as l,o as d,c as r,a2 as p}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"IP Geolocation மற்றும் User Management","description":"","frontmatter":{},"headers":[],"relativePath":"ta/Other/ip-geolocation-and-user-management.md","filePath":"ta/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),c={name:"ta/Other/ip-geolocation-and-user-management.md"};function u(g,e,h,m,b,f){return d(),r("div",null,[...e[0]||(e[0]=[p('<h1 id="ip-geolocation-மற்றும்-user-management" tabindex="-1">IP Geolocation மற்றும் User Management <a class="header-anchor" href="#ip-geolocation-மற்றும்-user-management" aria-label="Permalink to &quot;IP Geolocation மற்றும் User Management&quot;">​</a></h1><p>IP geolocation uploader records, login devices போன்ற logs-இல் உள்ள IP addresses-ஐ approximate locations ஆக மாற்றும்.</p><p>configure செய்த பிறகு admin panel upload மற்றும் access origins-ஐ தெளிவாக காட்டும். User Management மூலம் suspicious IP addresses-க்கு upload access block அல்லது restore செய்யலாம்.</p><h2 id="எங்கு-configure-செய்வது" tabindex="-1">எங்கு Configure செய்வது <a class="header-anchor" href="#எங்கு-configure-செய்வது" aria-label="Permalink to &quot;எங்கு Configure செய்வது&quot;">​</a></h2><p>திறக்கவும்:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; IP Geolocation</span></span></code></pre></div><p><img src="'+a+`" alt="IP geolocation" loading="lazy"></p><h2 id="available-settings" tabindex="-1">Available Settings <a class="header-anchor" href="#available-settings" aria-label="Permalink to &quot;Available Settings&quot;">​</a></h2><p>புதிய IP geolocation flow ஒரே map service-ஐ சாராமல் multiple sources support செய்கிறது.</p><table tabindex="0"><thead><tr><th>Setting</th><th>Purpose</th></tr></thead><tbody><tr><td>IP geolocation language</td><td>display language தேர்வு, உதா. English, Simplified Chinese, Japanese, French.</td></tr><tr><td>MaxMind Account ID</td><td>MaxMind GeoLite Web Service-க்கு MaxMind account ID.</td></tr><tr><td>MaxMind License Key</td><td>MaxMind License Key.</td></tr><tr><td>Tencent Map Key</td><td>Tencent Location Service key. Chinese addresses மற்றும் mainland China IPs-க்கு useful.</td></tr><tr><td>ipapi Key</td><td>APILayer ipapi key. multilingual IP geolocation support.</td></tr></tbody></table><p>தேவையான services மட்டும் நிரப்பவும். எல்லா fields-ஐயும் configure செய்ய வேண்டியதில்லை.</p><p>key எதுவும் இல்லாவிட்டாலும் ImgBed built-in free sources முயலும்; ஆனால் stability, language support, precision குறையலாம்.</p><h2 id="recommended-choices" tabindex="-1">Recommended Choices <a class="header-anchor" href="#recommended-choices" aria-label="Permalink to &quot;Recommended Choices&quot;">​</a></h2><p>Chinese addresses முக்கியம் என்றால்:</p><ol><li>IP geolocation language-ஐ Simplified Chinese ஆக அமைக்கவும்.</li><li>Tencent Map Key configure செய்யவும்.</li><li>optional-ஆக MaxMind அல்லது ipapi fallback source சேர்க்கவும்.</li></ol><p>English அல்லது multilingual addresses முக்கியம் என்றால்:</p><ol><li>தேவையான language தேர்வு செய்யவும்.</li><li>MaxMind Account ID மற்றும் License Key configure செய்யவும்.</li><li>multilingual results மேம்பட ipapi Key சேர்க்கவும்.</li></ol><h2 id="maxmind-setup" tabindex="-1">MaxMind Setup <a class="header-anchor" href="#maxmind-setup" aria-label="Permalink to &quot;MaxMind Setup&quot;">​</a></h2><p>MaxMind-க்கு:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>MaxMind dashboard-ல் account ID கண்டுபிடித்து License Keys page-ல் License Key generate செய்யவும்.</p><p><img src="`+t+'" alt="MaxMind key config" loading="lazy"></p><p>generation பிறகு Account ID மற்றும் License Key ImgBed-ல் paste செய்து save செய்யவும்.</p><p>MaxMind free plan daily use-க்கு பொருத்தம், ஆனால் request limits உள்ளன. quota exceed ஆனால் ImgBed மற்ற available sources முயலும்.</p><h2 id="ipapi-setup" tabindex="-1">ipapi Setup <a class="header-anchor" href="#ipapi-setup" aria-label="Permalink to &quot;ipapi Setup&quot;">​</a></h2><p>ipapi APILayer API Key பயன்படுத்தும்.</p><p>ipapi console திறந்து API Key copy செய்யவும்.</p><p><img src="'+s+'" alt="ipapi config" loading="lazy"></p><p>ImgBed <code>ipapi Key</code> field-ல் paste செய்து save செய்யவும்.</p><p>ipapi multilingual IP geolocation support செய்கிறது. selected language-ல் addresses வேண்டும் என்றால் useful. free plan-க்கும் request limits உள்ளன. quota முடிந்தால் ImgBed மற்ற sources முயலும்.</p><h2 id="tencent-map-key-setup" tabindex="-1">Tencent Map Key Setup <a class="header-anchor" href="#tencent-map-key-setup" aria-label="Permalink to &quot;Tencent Map Key Setup&quot;">​</a></h2><p>Tencent Map Key Chinese addresses, குறிப்பாக mainland China IPs-க்கு useful.</p><p>Tencent Location Service-ல் key உருவாக்கும்போது enable செய்யவும்:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebServiceAPI</span></span></code></pre></div><p>creation பிறகு key-ஐ <code>Tencent Map Key</code>-ல் paste செய்து save செய்யவும்.</p><p>basic Chinese IP geolocation மட்டும் வேண்டுமானால் Tencent Map Key போதும்.</p><h2 id="user-management-ல்-என்ன-பார்க்க-வேண்டும்" tabindex="-1">User Management-ல் என்ன பார்க்க வேண்டும் <a class="header-anchor" href="#user-management-ல்-என்ன-பார்க்க-வேண்டும்" aria-label="Permalink to &quot;User Management-ல் என்ன பார்க்க வேண்டும்&quot;">​</a></h2><p>User Management admin panel மேல் பகுதியிலிருந்து கிடைக்கும்.</p><p><img src="'+i+'" alt="User management" loading="lazy"></p><p>User Management IP அடிப்படையில் upload activity காட்டும்:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>IP source</td><td>uploader source IP.</td></tr><tr><td>Address</td><td>IP-இல் இருந்து resolve ஆன approximate location.</td></tr><tr><td>Total upload size</td><td>இந்த IP upload செய்த total file size.</td></tr><tr><td>Upload count</td><td>இந்த IP upload செய்த எண்ணிக்கை.</td></tr><tr><td>Upload allowed</td><td>On என்றால் uploads allowed. Off என்றால் blocked.</td></tr></tbody></table><p>இடது arrow கிளிக் செய்து அந்த IP upload செய்த files list expand செய்யவும்.</p><p>file list file name, preview, file size, moderation result, file status, upload time காட்டும். upload suspicious என்றால் முதலில் IP expand செய்து files review செய்து பிறகு further uploads block செய்யலாமா முடிவு செய்யவும்.</p><p>IP suspicious என்றால் <code>Upload allowed</code> off செய்யவும். அந்த IP-இல் இருந்து future uploads blocked ஆகும்.</p><h2 id="search-sort-advanced-filters" tabindex="-1">Search, Sort, Advanced Filters <a class="header-anchor" href="#search-sort-advanced-filters" aria-label="Permalink to &quot;Search, Sort, Advanced Filters&quot;">​</a></h2><p>User Management மேல் பகுதியில் IP source அல்லது address மூலம் search செய்யலாம்.</p><p>recent uploaders, high-frequency uploaders, high-usage IPs கண்டறிய time, upload count, total upload size மூலம் sort செய்யலாம்.</p><p>மேலும் ஆய்வு செய்ய advanced filters திறக்கவும்.</p><p><img src="'+n+'" alt="Advanced filters" loading="lazy"></p><p>Advanced filters:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Usage</th></tr></thead><tbody><tr><td>Time range</td><td>selected period-ல் files upload செய்த IPs.</td></tr><tr><td>Access status</td><td>normal, blocked போன்ற states.</td></tr><tr><td>Allow/block list</td><td>allowlist, blocklist, unset.</td></tr><tr><td>File type</td><td>images, videos, audio, documents, code, other files.</td></tr><tr><td>File size</td><td>uploaded file size range.</td></tr><tr><td>Age rating</td><td>unset, General, R12+, R16+, R18 போன்ற ratings.</td></tr><tr><td>File status</td><td>abnormal files ஆய்வு செய்ய current file status.</td></tr></tbody></table><p><code>Apply Filters</code> கிளிக் செய்து apply செய்யவும். <code>Reset</code> மூலம் எல்லா data-க்கும் திரும்பலாம்.</p><h2 id="mobile-view" tabindex="-1">Mobile View <a class="header-anchor" href="#mobile-view" aria-label="Permalink to &quot;Mobile View&quot;">​</a></h2><p>mobile-ல் User Management card layout ஆக மாறும்.</p><p><img src="'+o+`" alt="Mobile user management" loading="lazy"></p><p>ஒவ்வொரு card IP, address, total upload size, upload count, upload allowed switch காட்டும். horizontal table scrolling இல்லாமல் manage செய்யலாம்.</p><h2 id="location-தவறாக-தெரிந்தால்" tabindex="-1">Location தவறாக தெரிந்தால் <a class="header-anchor" href="#location-தவறாக-தெரிந்தால்" aria-label="Permalink to &quot;Location தவறாக தெரிந்தால்&quot;">​</a></h2><p>IP geolocation approximate. இது precise street address அல்ல.</p><p>user proxy, data center, cloud server, cross-border network பின்னால் இருந்தால் location வேறுபடலாம்.</p><p>rough origin புரிய, abnormal uploads கண்டறிய, blocking decisions உதவ இதை பயன்படுத்தவும். precise tracking என கருத வேண்டாம்.</p><h2 id="common-cases" tabindex="-1">Common Cases <a class="header-anchor" href="#common-cases" aria-label="Permalink to &quot;Common Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Case</th><th>Meaning</th></tr></thead><tbody><tr><td>Address empty</td><td>IP இன்னும் resolve ஆகவில்லை, அல்லது current source unavailable.</td></tr><tr><td>Address language wrong</td><td>IP geolocation language மற்றும் அந்த language support source configured உள்ளதா பார்க்கவும்.</td></tr><tr><td>Address data center காட்டுகிறது</td><td>proxies, cloud servers, crawlers பல data center/ISP addresses ஆக தெரியும்.</td></tr><tr><td>Upload count high</td><td>IP-ஐ கவனமாக review செய்து தேவையெனில் uploads block செய்யவும்.</td></tr><tr><td>Total upload size large</td><td>sort/filter செய்து IP expand செய்து specific files inspect செய்யவும்.</td></tr><tr><td>blocking பிறகு restore</td><td><code>Upload allowed</code> மீண்டும் on செய்யவும்.</td></tr></tbody></table><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Other Settings-ல் IP Geolocation திறக்கவும்</span></span>
<span class="line"><span>-&gt; IP geolocation language தேர்வு செய்யவும்</span></span>
<span class="line"><span>-&gt; தேவையான MaxMind, Tencent Map, ipapi credentials நிரப்பவும்</span></span>
<span class="line"><span>-&gt; settings save செய்யவும்</span></span>
<span class="line"><span>-&gt; User Management திறக்கவும்</span></span>
<span class="line"><span>-&gt; IP source, address, total upload size, upload count review செய்யவும்</span></span>
<span class="line"><span>-&gt; abnormal IPs கண்டறிய search, sort, advanced filters பயன்படுத்தவும்</span></span>
<span class="line"><span>-&gt; தேவைக்கேற்ப uploads allow/block செய்யவும்</span></span></code></pre></div>`,64)])])}const x=l(c,[["render",u]]);export{v as __pageData,x as default};
